insert into practice_context_blocks (id, exercise_id, label, image_url, text_content, block_type) values
  ('a1b2c3d4-0002-4000-8000-000000000001', 'a1b2c3d4-0001-4000-8000-000000000001', $$figuur 1 en tabel — productieproces polycarbonaat$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-i-groene-chemie-met-dimethylcarbonaat-context1.png$$,
   $$Polycarbonaat is een veelgebruikte kunststof die wordt verwerkt in de omhulsels van elektronische apparatuur en in auto’s. Begin deze eeuw werd het grootste deel van alle polycarbonaat nog geproduceerd door middel van de condensatie-polymerisatie van bisfenol-A en fosgeen. De totaalvergelijking van alle reacties in dit productieproces van polycarbonaat is in figuur 1 vereenvoudigd weergegeven.

figuur 1: n HO-C₆H₄-C(CH₃)₂-C₆H₄-OH (bisfenol-A) + n Cl-C(=O)-Cl (fosgeen) + 2n NaOH → –(O-C₆H₄-C(CH₃)₂-C₆H₄-O-C(=O)–)n (monomeereenheid van polycarbonaat) + 2n NaCl + 2n H₂O

Bij dit productieproces worden de beginstoffen gemengd volgens de molverhoudingen in figuur 1. De molaire massa’s van de stoffen uit figuur 1 zijn in de tabel gegeven.

tabel — molaire massa (g mol⁻¹): bisfenol-A 228; fosgeen 98,9; NaOH 40,0; monomeereenheid polycarbonaat 254; NaCl 58,4; H₂O 18,0.

Dit productieproces heeft een rendement van 92%.$$, 'inline'),
  ('a1b2c3d4-0002-4000-8000-000000000002', 'a1b2c3d4-0001-4000-8000-000000000001', $$figuur 2 — reactie 1 (vorming DMC in R1)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-i-groene-chemie-met-dimethylcarbonaat-context2.png$$,
   $$Bij dit proces komt een grote hoeveelheid afval vrij. In een studie is een nieuw productieproces onderzocht dat minder afval veroorzaakt. In het onderzochte proces wordt eerst dimethylcarbonaat (DMC) uit methanol gevormd. Op de uitwerkbijlage bij vraag 7 is het blokschema van het nieuwe proces onvolledig weergegeven. In figuur 2 is reactie 1 gegeven, dit is de reactie die in reactor 1 (R1) verloopt.$$, 'inline'),
  ('a1b2c3d4-0002-4000-8000-000000000003', 'a1b2c3d4-0001-4000-8000-000000000001', $$reactiewarmte en vormingswarmte CH₃OH$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-i-groene-chemie-met-dimethylcarbonaat-context3.png$$,
   $$De reactiewarmte van de reactie naar rechts is +0,67·10⁵ J per mol DMC. De vormingswarmte van CH₃OH (g) bedraagt –2,02·10⁵ J mol⁻¹.$$, 'inline'),
  ('a1b2c3d4-0002-4000-8000-000000000004', 'a1b2c3d4-0001-4000-8000-000000000001', $$energiediagrammen met/zonder katalysator (toelichting)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-i-groene-chemie-met-dimethylcarbonaat-context4.png$$,
   $$Om een zo hoog mogelijke omzettingssnelheid te bereiken, is in het onderzoek gebruikgemaakt van een katalysator voor reactie 1. Op de uitwerkbijlage is in diagram 1 het energiediagram van de vorming van DMC zonder katalysator onvolledig weergegeven. Daarnaast is in diagram 2 het energiediagram van de vorming van DMC mét katalysator onvolledig weergegeven. In beide diagrammen ontbreken de energieniveaus van de geactiveerde toestand en die van de reactieproducten. Beide diagrammen zijn op dezelfde schaal weergegeven.$$, 'inline'),
  ('a1b2c3d4-0002-4000-8000-000000000005', 'a1b2c3d4-0001-4000-8000-000000000001', $$uitwerkbijlage vraag 3 — energiediagrammen (zonder/met katalysator)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-i-groene-chemie-met-dimethylcarbonaat-context5.png$$,
   $$uitwerkbijlage bij vraag 3: diagram 1 (zonder katalysator) en diagram 2 (met katalysator), elk met de assen energie (verticaal) en reactieverloop (horizontaal) en het energieniveau van de beginstoffen reeds ingetekend. De energieniveaus van de geactiveerde toestand en van de reactieproducten ontbreken nog.$$, 'uitwerkbijlage'),
  ('a1b2c3d4-0002-4000-8000-000000000006', 'a1b2c3d4-0001-4000-8000-000000000001', $$toevoeging cyanopyridine aan R1$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-i-groene-chemie-met-dimethylcarbonaat-context6.png$$,
   $$In R1 wordt ook continu de stof cyanopyridine toegevoegd. Deze stof reageert met het in reactie 1 gevormde water. De toevoer van cyanopyridine is zo afgesteld dat geen water R1 verlaat.$$, 'inline'),
  ('a1b2c3d4-0002-4000-8000-000000000007', 'a1b2c3d4-0001-4000-8000-000000000001', $$vorming picolinamide en scheiding in S1$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-i-groene-chemie-met-dimethylcarbonaat-context7.png$$,
   $$In R1 reageert 1 mol cyanopyridine met 1 mol water, waarbij uitsluitend 1 mol picolinamide wordt gevormd. De structuurformule van picolinamide is hiernaast weergegeven (een pyridinering met aan de ring een –C(=O)NH₂-groep).

In scheidingsruimte 1 (S1) wordt het reactiemengsel gescheiden door middel van destillatie. De overmaat CO₂ en methanol wordt als twee aparte stofstromen gerecirculeerd naar R1. De overige stoffen worden gescheiden in afzonderlijke stromen, te weten DMC, cyanopyridine en picolinamide. In R1 ontstaan ook NH₃ en andere bijproducten, die de fabriek verlaten als afval.

De cyanopyridine en picolinamide hebben de hoogste kookpunten van de aanwezige stoffen. Het picolinamide verlaat S1 aan de onderzijde omdat het een hoger kookpunt heeft dan cyanopyridine.$$, 'inline'),
  ('a1b2c3d4-0002-4000-8000-000000000008', 'a1b2c3d4-0001-4000-8000-000000000001', $$reactor 4 — terugwinning cyanopyridine$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-i-groene-chemie-met-dimethylcarbonaat-context8.png$$,
   $$Het in R1 ontstane picolinamide wordt in reactor 4 volledig omgezet tot water en cyanopyridine. De cyanopyridine wordt hergebruikt, terwijl het water als afvalstroom de fabriek verlaat. In R4 zijn de omstandigheden zo gekozen dat de reactieproducten als gescheiden stofstromen vrijkomen. In het blokschema op de uitwerkbijlage ontbreken R4 en de stofstromen van cyanopyridine, picolinamide en water.$$, 'inline'),
  ('a1b2c3d4-0002-4000-8000-000000000009', 'a1b2c3d4-0001-4000-8000-000000000001', $$uitwerkbijlage vraag 7 — blokschema productieproces$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-i-groene-chemie-met-dimethylcarbonaat-context9.png$$,
   $$uitwerkbijlage bij vraag 7: onvolledig blokschema van het productieproces. Weergegeven zijn onder meer: instroom methanol en CO₂ naar R1; R1 met uitgaande stofstromen CO₂, NH₃ en DMC naar S1; S1 met uitgaande stromen methanol (recirculatie naar R1), bijproducten, en DMC naar R2; R2 (met invoer methanol naar R1) leidend via DMC naar R2, DMC → R2 → S2 → R3 (met invoer bisfenol-A) → S3 → polycarbonaat, met fenol uit S3 terug gerecirculeerd. Reactor R4 en de stofstromen van cyanopyridine, picolinamide en water tussen S1 en R4 ontbreken nog en moeten door de kandidaat worden ingetekend.$$, 'uitwerkbijlage'),
  ('a1b2c3d4-0002-4000-8000-000000000010', 'a1b2c3d4-0001-4000-8000-000000000001', $$figuur 3 — reactie 2 en reactie 3 (DPC en polycarbonaat)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-i-groene-chemie-met-dimethylcarbonaat-context10.png$$,
   $$De stroom van DMC uit S1 wordt doorgevoerd naar reactor 2 (R2). In R2 verloopt reactie 2, waarbij het tussenproduct DPC wordt gevormd. In reactor 3 (R3) wordt uiteindelijk via reactie 3 het polycarbonaat gevormd. In figuur 3 zijn beide reacties weergegeven.$$, 'inline'),
  ('a1b2c3d4-0002-4000-8000-000000000011', 'a1b2c3d4-0001-4000-8000-000000000001', $$rendement, methanolrecirculatie en stof Z$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-i-groene-chemie-met-dimethylcarbonaat-context11.png$$,
   $$Reactie 2 en reactie 3 verlopen met een rendement van 100%. In het proces bevinden zich de scheidingsruimten S2 en S3. In S2 wordt het methanol gescheiden van het DPC en in S3 wordt het fenol gescheiden van het polycarbonaat.

Het methanol afkomstig uit S1 en S2 wordt gerecirculeerd naar R1. In een van de nevenreacties in R1 ontstaan ammoniak en stof Z. De structuurformule van stof Z is hiernaast weergegeven (een pyridinering met aan de ring een –C(=O)-O-CH₃-groep).

De stofstromen van methanol naar R1 zijn in het blokschema bij vraag 7 onvolledig weergegeven. Bij scheidingsprocessen treedt geen verlies van methanol op.$$, 'inline'),
  ('a1b2c3d4-0002-4000-8000-000000000012', 'a1b2c3d4-0001-4000-8000-000000000002', $$figuur 1 — vorming natuurrubber uit isopreen$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-i-autobanden-context1.png$$,
   $$Het rubber van een autoband bestaat uit een mengsel van verschillende polymeren, waaronder natuurrubber. Natuurrubber kan worden opgevat als een polymeer van isopreen (2-methylbuta-1,3-dieen). De vorming van natuurrubber uit isopreen is in figuur 1 schematisch weergegeven. De polymeerketens in natuurrubber ontstaan door cis-1,4-additie van isopreen. De isopreen-eenheden worden dan aan elkaar gebonden via de koolstofatomen C1 en C4 van isopreen. De koolstofatomen C1 en C4 rondom de dubbele bindingen in natuurrubber staan uitsluitend in de cis-configuratie.

In autobanden wordt ook synthetisch poly-isopreen verwerkt. Bij de productie van synthetisch poly-isopreen worden polymeerketens gevormd waarbij de monomeer-eenheden op vier verschillende manieren in de keten zijn opgenomen. Behalve de cis-1,4-additie verlopen er namelijk ook andere additiereacties.$$, 'inline'),
  ('a1b2c3d4-0002-4000-8000-000000000013', 'a1b2c3d4-0001-4000-8000-000000000002', $$figuur 2 — kristallijne gebieden bij oprekken$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-i-autobanden-context2.png$$,
   $$In figuur 2 is weergegeven dat de polymeerketens in natuurrubber in opgerolde vorm voorkomen. Ook is weergegeven dat wanneer natuurrubber wordt opgerekt, de ketens zich gedeeltelijk strekken. Hierdoor worden zogeheten kristallijne gebieden gevormd. Bij synthetisch poly-isopreen is het aandeel kristallijne gebieden dat bij het oprekken wordt gevormd kleiner.$$, 'inline'),
  ('a1b2c3d4-0002-4000-8000-000000000014', 'a1b2c3d4-0001-4000-8000-000000000002', $$kristallijne gebieden en vervorming$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-i-autobanden-context3.png$$,
   $$Doordat de kristallijne gebieden ontstaan in het rubber, zijn de delen van de autoband waarin natuurrubber is verwerkt beter bestand tegen vervorming. Dit kan worden verklaard met behulp van de interacties tussen de polymeerketens. In de ongeordende gebieden en in de kristallijne gebieden zijn de sterktes van deze interacties verschillend.$$, 'inline'),
  ('a1b2c3d4-0002-4000-8000-000000000015', 'a1b2c3d4-0001-4000-8000-000000000002', $$SBR — massaverhouding styreen en buta-1,3-dieen$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-i-autobanden-context4.png$$,
   $$Behalve natuurrubber bevat een autoband ook SBR. SBR is een copolymeer van styreen (fenyletheen, C₈H₈) en buta-1,3-dieen (C₄H₆) in de massaverhouding 25 : 75.$$, 'inline'),
  ('a1b2c3d4-0002-4000-8000-000000000016', 'a1b2c3d4-0001-4000-8000-000000000002', $$figuur 3 — vorming crosslinks met zwavel$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-i-autobanden-context5.png$$,
   $$In de volgende stap van de fabricage van autobanden worden crosslinks gevormd tussen de copolymeerketens door toevoeging van zwavel. De zwavel wordt in een mal gemengd met natuurrubber en SBR. Vervolgens wordt het mengsel enige tijd op een hoge temperatuur gehouden, waarbij de crosslinks worden gevormd. Alleen onverzadigde polymeren kunnen met zwavel crosslinks vormen. De vorming van crosslinks is in figuur 3 schematisch weergegeven.$$, 'inline'),
  ('a1b2c3d4-0002-4000-8000-000000000017', 'a1b2c3d4-0001-4000-8000-000000000002', $$reactiemechanisme radicaalvorming (C–H-splitsing)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-i-autobanden-context6.png$$,
   $$In de eerste stap van het reactiemechanisme van de vorming van crosslinks wordt een C–H-binding op C1 verbroken. Hierbij wordt een H• radicaal afgesplitst zodat op C1 een ongepaard elektron overblijft. Van het in het polymeer gevormde radicaal bestaan twee grensstructuren. Beide grensstructuren zijn op de uitwerkbijlage onvolledig weergegeven.$$, 'inline'),
  ('a1b2c3d4-0002-4000-8000-000000000018', 'a1b2c3d4-0001-4000-8000-000000000002', $$uitwerkbijlage vraag 13 — grensstructuren radicaal$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-i-autobanden-context7.png$$,
   $$uitwerkbijlage bij vraag 13: twee onvolledig weergegeven grensstructuren (mesomere structuren) van het radicaal dat in het polymeer is gevormd na afsplitsing van een H• radicaal op C1.$$, 'uitwerkbijlage'),
  ('a1b2c3d4-0002-4000-8000-000000000019', 'a1b2c3d4-0001-4000-8000-000000000003', $$figuur 1 — structuurformules picoline en niacine$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-i-niacine-context1.png$$,
   $$Niacine (vitamine B3) is een vitamine die van belang is voor het functioneren van een groot deel van de enzymsystemen in het lichaam. Er bestaan productieprocessen om niacine uit goedkope fossiele grondstoffen te produceren. In de eerste stap van zo’n proces wordt picoline gevormd. In de tweede stap wordt picoline omgezet tot niacine. De structuurformules van picoline en niacine zijn in figuur 1 weergegeven (picoline: een pyridinering met een –CH₃-groep; niacine: een pyridinering met een –COOH-groep).$$, 'inline'),
  ('a1b2c3d4-0002-4000-8000-000000000020', 'a1b2c3d4-0001-4000-8000-000000000003', $$vorming picoline uit propanal, prop-2-enal en ammoniak$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-i-niacine-context2.png$$,
   $$In de eerste stap wordt picoline gemaakt uit propanal, prop-2-enal en ammoniak. Prop-2-enal is een aldehyde met molecuulformule C₃H₄O. In deze reactie worden behalve picoline ook water en nog één andere stof gevormd.$$, 'inline'),
  ('a1b2c3d4-0002-4000-8000-000000000021', 'a1b2c3d4-0001-4000-8000-000000000003', $$figuur 2 — biosynthese quinolinezuur$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-i-niacine-context3.png$$,
   $$Niacine kan ook worden gemaakt op basis van de stof quinolinezuur waarbij wordt gebruikgemaakt van micro-organismen. Om de productie van quinolinezuur in het micro-organisme zo hoog mogelijk te maken, hebben onderzoekers genetisch gemodificeerde micro-organismen gekweekt. Als gevolg van de modificatie scheiden deze micro-organismen meer quinolinezuur uit. In figuur 2 is deze biosynthese schematisch weergegeven: binnen de cel wordt Asp (asparaginezuur) via enzym P omgezet tot stof Y; stof Y reageert vervolgens spontaan (zonder enzym) verder tot nevenproducten, of wordt via enzym Q omgezet tot quinolinezuur (een pyridinering met twee –COOH-groepen); quinolinezuur wordt op zijn beurt via enzym R omgezet tot nicotinamides. Een deel van het gevormde quinolinezuur verlaat de cel (transport) en wordt buiten de cel omgezet tot niacine + CO₂.$$, 'inline'),
  ('a1b2c3d4-0002-4000-8000-000000000022', 'a1b2c3d4-0001-4000-8000-000000000003', $$doelstellingen enzymconcentraties P, Q en R$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-i-niacine-context4.png$$,
   $$Stof Y wordt door enzym Q omgezet tot quinolinezuur. Stof Y reageert echter ook snel en zonder hulp van enzymen tot allerlei nevenproducten. De snelheid van iedere enzymatische omzetting in dit proces wordt bepaald door de concentratie van het betrokken enzym. In de genetisch gemodificeerde micro-organismen waren de concentraties van de enzymen P, Q en R afwijkend. Hierbij waren er twee doelstellingen: 1) zo min mogelijk andere stoffen dan quinolinezuur produceren; 2) zo veel mogelijk quinolinezuur per tijdseenheid produceren. Bij een presentatie van het onderzoek gebruikten de onderzoekers een tabel waaruit blijkt hoe de concentratie van elk enzym moest veranderen om beide doelstellingen te realiseren. Op de uitwerkbijlage is deze tabel onvolledig weergegeven.$$, 'inline'),
  ('a1b2c3d4-0002-4000-8000-000000000023', 'a1b2c3d4-0001-4000-8000-000000000003', $$uitwerkbijlage vraag 15 — tabel enzymconcentraties$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-i-niacine-context5.png$$,
   $$uitwerkbijlage bij vraag 15: tabel met rijen voor de enzymen P, Q en R, en kolommen ‘concentratie lager dan normaal’, ‘concentratie hoger dan normaal’ en ‘concentratie veel hoger dan normaal’. Achter elk enzym moet één kruisje in de juiste kolom worden gezet, zodanig dat elke kolom precies één kruisje bevat.$$, 'uitwerkbijlage'),
  ('a1b2c3d4-0002-4000-8000-000000000024', 'a1b2c3d4-0001-4000-8000-000000000003', $$molverhouding en massagegevens omzetting quinolinezuur$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-i-niacine-context6.png$$,
   $$Alle stoffen in figuur 2 reageren in de molverhouding 1:1. In figuur 2 is ook aangegeven dat een deel van het gevormde quinolinezuur de cel verlaat. Bij een van de proeven werd zo een oplossing met daarin 5,5 g quinolinezuur verkregen. Het quinolinezuur werd vervolgens door de onderzoekers omgezet tot niacine. Hierbij werd 3,8 g niacine gevormd.$$, 'inline'),
  ('a1b2c3d4-0002-4000-8000-000000000025', 'a1b2c3d4-0001-4000-8000-000000000003', $$figuur 3 — zuur-baseevenwicht niacine en Kz$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-i-niacine-context7.png$$,
   $$Halverwege de twintigste eeuw is ontdekt dat niacine ook kan worden toegepast als geneesmiddel. Uit onderzoek naar de werking van niacine bleek dat het zuurrest-ion van niacine aan een receptoreiwit bindt. Niacine is een zwak zuur. In water treedt het evenwicht uit figuur 3 op (HNic ⇌ H⁺ + Nic⁻).

De pH in de vloeistof rondom het receptoreiwit is zodanig, dat meer dan 90% van alle niacine-deeltjes voorkomt als zuurrest-ion. De waarde van de Kz van niacine bij de heersende omstandigheden is 1,3·10⁻⁵.$$, 'inline'),
  ('a1b2c3d4-0002-4000-8000-000000000026', 'a1b2c3d4-0001-4000-8000-000000000003', $$figuur 4 — coderende DNA-streng receptoreiwit$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-i-niacine-context8.png$$,
   $$In figuur 4 is een gedeelte van de coderende streng van het menselijk DNA weergegeven, beginnend bij de base met nummer 1072. De code voor het receptoreiwit begint bij de base met nummer 1. In het weergegeven gedeelte bevindt zich het stopcodon voor het receptoreiwit.$$, 'inline'),
  ('a1b2c3d4-0002-4000-8000-000000000027', 'a1b2c3d4-0001-4000-8000-000000000004', $$figuur 1 — vorming polymeer uit monomeren (pleister)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-i-een-pleister-voor-stroom-context1.png$$,
   $$Onderzoekers hebben een pleister ontwikkeld die stroom kan opwekken als hij op de huid is geplakt. Op de pleister is een brandstofcel aangebracht. Met de geleverde energie kunnen bijvoorbeeld medische sensoren worden gevoed. De elektrodes van de brandstofcel zijn aangebracht op een onderlaag van een niet-geleidend polymeer. De vorming van dit polymeer uit de monomeren is in figuur 1 vereenvoudigd weergegeven.$$, 'inline'),
  ('a1b2c3d4-0002-4000-8000-000000000028', 'a1b2c3d4-0001-4000-8000-000000000004', $$toelichting uitwerkbijlage vraag 21 (mechanisme)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-i-een-pleister-voor-stroom-context2.png$$,
   $$Op de uitwerkbijlage is het mechanisme van een van de stappen in de vorming van het polymeer onvolledig weergegeven.$$, 'inline'),
  ('a1b2c3d4-0002-4000-8000-000000000029', 'a1b2c3d4-0001-4000-8000-000000000004', $$uitwerkbijlage vraag 21 — reactiemechanisme polymerisatie$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-i-een-pleister-voor-stroom-context3.png$$,
   $$uitwerkbijlage bij vraag 21: onvolledig weergegeven mechanisme van één stap in de vorming van het polymeer, met een omkaderd deel waarin de niet-bindende elektronenparen en de vloeipijlen (die de verplaatsing van elektronenparen tijdens de reactie weergeven) nog moeten worden ingetekend.$$, 'uitwerkbijlage'),
  ('a1b2c3d4-0002-4000-8000-000000000030', 'a1b2c3d4-0001-4000-8000-000000000004', $$figuur 2 — elektrodereacties brandstofcel$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-i-een-pleister-voor-stroom-context4.png$$,
   $$Op de onderlaag zijn poreuze elektrodes aangebracht. Op de negatieve elektrodes is het enzym lactaat-oxidase (LOx) aanwezig. Op de positieve elektrodes is Ag₂O aangebracht. In figuur 2 is schematisch weergegeven welke reacties in de elektrodes verlopen.$$, 'inline'),
  ('a1b2c3d4-0002-4000-8000-000000000031', 'a1b2c3d4-0001-4000-8000-000000000004', $$melkzuur, lactaat en LOx in zweet$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-i-een-pleister-voor-stroom-context5.png$$,
   $$Tijdens lichamelijke inspanning ontstaat in de spieren melkzuur (2-hydroxypropaanzuur, C₃H₆O₃). Een deel van het melkzuur wordt met het zweet uitgescheiden. In zweet bevinden zich hierdoor H⁺-ionen en lactaat-ionen (de zuurrest-ionen van melkzuur). Het enzym (LOx) maakt de omzetting van de lactaat-ionen naar C₃H₃O₃⁻-ionen mogelijk.$$, 'inline'),
  ('a1b2c3d4-0002-4000-8000-000000000032', 'a1b2c3d4-0001-4000-8000-000000000004', $$figuur 3 — stroomsterkte versus concentratie lactaat$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-i-een-pleister-voor-stroom-context6.png$$,
   $$De onderzoekers hebben onderzocht hoe de stroomsterkte I afhangt van de concentratie lactaat. In figuur 3 zijn de resultaten van hun metingen vereenvoudigd weergegeven.$$, 'inline'),
  ('a1b2c3d4-0002-4000-8000-000000000033', 'a1b2c3d4-0001-4000-8000-000000000004', $$herinterpretatie figuur 3 als reactiesnelheid$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-i-een-pleister-voor-stroom-context7.png$$,
   $$Figuur 3 kan ook worden gelezen als een diagram waarin de reactiesnelheid van de omzetting van lactaat is uitgezet tegen de concentratie lactaat. Men zorgde ervoor dat tijdens het experiment de hoeveelheid Ag₂O en enzym niet veranderde.$$, 'inline'),
  ('a1b2c3d4-0002-4000-8000-000000000034', 'a1b2c3d4-0001-4000-8000-000000000004', $$praktijkproef — lading en tijdsduur$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-i-een-pleister-voor-stroom-context8.png$$,
   $$In een praktijkproef werd een pleister op de arm van een sporter bevestigd. Tijdens lichamelijke inspanning werd gedurende 10 minuten gemiddeld een lading van 1,2·10⁻³ C per seconde getransporteerd. Een mol elektronen heeft een lading van 9,65·10⁴ C.$$, 'inline');

insert into practice_questions (id, exercise_id, question_number, topics, question_image_url, question_text, context_block_ids) values
  ('a1b2c3d4-0003-4000-8000-000000000001', 'a1b2c3d4-0001-4000-8000-000000000001', 1,
   '[{"domain": "Technologie en duurzaamheid", "subdomain": "Groene energie en duurzaamheid"}, {"domain": "Rekenen en analyse", "subdomain": "Molaire massa en molariteit"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-i-groene-chemie-met-dimethylcarbonaat-vraag1.png$$, $$Bereken de E-factor van dit productieproces van polycarbonaat.$$, array['a1b2c3d4-0002-4000-8000-000000000001']::uuid[]),
  ('a1b2c3d4-0003-4000-8000-000000000002', 'a1b2c3d4-0001-4000-8000-000000000001', 2,
   '[{"domain": "Reacties", "subdomain": "Exotherme en endotherme reacties"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-i-groene-chemie-met-dimethylcarbonaat-vraag2.png$$, $$Bereken de vormingswarmte van DMC.$$, array['a1b2c3d4-0002-4000-8000-000000000002', 'a1b2c3d4-0002-4000-8000-000000000003']::uuid[]),
  ('a1b2c3d4-0003-4000-8000-000000000003', 'a1b2c3d4-0001-4000-8000-000000000001', 3,
   '[{"domain": "Reacties", "subdomain": "Exotherme en endotherme reacties"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-i-groene-chemie-met-dimethylcarbonaat-vraag3.png$$, $$Laat zien welke invloed de katalysator heeft op reactie 1, door op de uitwerkbijlage in beide energiediagrammen de ontbrekende energieniveaus met bijbehorende bijschriften te tekenen.$$, array['a1b2c3d4-0002-4000-8000-000000000002', 'a1b2c3d4-0002-4000-8000-000000000004', 'a1b2c3d4-0002-4000-8000-000000000005']::uuid[]),
  ('a1b2c3d4-0003-4000-8000-000000000004', 'a1b2c3d4-0001-4000-8000-000000000001', 4,
   '[{"domain": "Reacties", "subdomain": "Chemisch evenwicht en evenwichtsconstante"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-i-groene-chemie-met-dimethylcarbonaat-vraag4.png$$, $$Geef de evenwichtsvoorwaarde voor reactie 1. Gebruik DMC als aanduiding voor dimethylcarbonaat.$$, array['a1b2c3d4-0002-4000-8000-000000000002']::uuid[]),
  ('a1b2c3d4-0003-4000-8000-000000000005', 'a1b2c3d4-0001-4000-8000-000000000001', 5,
   '[{"domain": "Reacties", "subdomain": "Chemisch evenwicht en evenwichtsconstante"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-i-groene-chemie-met-dimethylcarbonaat-vraag5.png$$, $$Leg uit dat het toevoegen van de stof cyanopyridine het rendement van de vorming van dimethylcarbonaat verhoogt.$$, array['a1b2c3d4-0002-4000-8000-000000000002', 'a1b2c3d4-0002-4000-8000-000000000006']::uuid[]),
  ('a1b2c3d4-0003-4000-8000-000000000006', 'a1b2c3d4-0001-4000-8000-000000000001', 6,
   '[{"domain": "Materie", "subdomain": "Moleculaire structuur en ruimtelijke bouw"}, {"domain": "Materie", "subdomain": "Bindingen en stofeigenschappen"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-i-groene-chemie-met-dimethylcarbonaat-vraag6.png$$, $$Voer de volgende opdrachten uit:
− Teken de structuurformule van cyanopyridine.
− Verklaar dat het kookpunt van picolinamide hoger is dan dat van cyanopyridine. Gebruik hierbij begrippen op microniveau.$$, array['a1b2c3d4-0002-4000-8000-000000000007']::uuid[]),
  ('a1b2c3d4-0003-4000-8000-000000000007', 'a1b2c3d4-0001-4000-8000-000000000001', 7,
   '[{"domain": "Technologie en duurzaamheid", "subdomain": "Blokschema van een chemisch proces"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-i-groene-chemie-met-dimethylcarbonaat-vraag7.png$$, $$Maak het blokschema op de uitwerkbijlage compleet.
− Teken R4.
− Teken de ontbrekende stofstromen van cyanopyridine, picolinamide en water. Houd daarbij rekening met hergebruik van stoffen.
− Je hoeft niets aan te geven tussen R1 en S1.
− Geef de stoffen in het schema weer met de volgende cijfers:
1 cyanopyridine
2 picolinamide
3 water$$, array['a1b2c3d4-0002-4000-8000-000000000002', 'a1b2c3d4-0002-4000-8000-000000000006', 'a1b2c3d4-0002-4000-8000-000000000007', 'a1b2c3d4-0002-4000-8000-000000000008', 'a1b2c3d4-0002-4000-8000-000000000009']::uuid[]),
  ('a1b2c3d4-0003-4000-8000-000000000008', 'a1b2c3d4-0001-4000-8000-000000000001', 8,
   '[{"domain": "Reacties", "subdomain": "Reactievergelijkingen opstellen"}, {"domain": "Technologie en duurzaamheid", "subdomain": "Reactoren en scheidingsinstallaties"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-i-groene-chemie-met-dimethylcarbonaat-vraag8.png$$, $$Leid af met behulp van de reacties die optreden in R1 en R2 of de recirculatie van methanol van S1 en S2 naar R1 een gesloten systeem is, of dat er in het proces netto methanol wordt verbruikt.$$, array['a1b2c3d4-0002-4000-8000-000000000002', 'a1b2c3d4-0002-4000-8000-000000000010', 'a1b2c3d4-0002-4000-8000-000000000011']::uuid[]),
  ('a1b2c3d4-0003-4000-8000-000000000009', 'a1b2c3d4-0001-4000-8000-000000000002', 9,
   '[{"domain": "Materie", "subdomain": "Isomeren (cis-trans en spiegelbeeld)"}, {"domain": "Materie", "subdomain": "Polymeren, legeringen en keramische materialen"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-i-autobanden-vraag9.png$$, $$Teken de structuurformules van de drie andere monomeereenheden die voorkomen in synthetisch poly-isopreen. Neem aan dat er geen crosslinks worden gevormd.$$, array['a1b2c3d4-0002-4000-8000-000000000012']::uuid[]),
  ('a1b2c3d4-0003-4000-8000-000000000010', 'a1b2c3d4-0001-4000-8000-000000000002', 10,
   '[{"domain": "Materie", "subdomain": "Polymeren, legeringen en keramische materialen"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-i-autobanden-vraag10.png$$, $$Voer de volgende opdrachten uit:
− Verklaar dat kristallijne gebieden zich kunnen vormen bij het oprekken van natuurrubber.
− Verklaar dat bij synthetisch poly-isopreen het aandeel kristallijne gebieden bij het oprekken kleiner is.$$, array['a1b2c3d4-0002-4000-8000-000000000012', 'a1b2c3d4-0002-4000-8000-000000000013']::uuid[]),
  ('a1b2c3d4-0003-4000-8000-000000000011', 'a1b2c3d4-0001-4000-8000-000000000002', 11,
   '[{"domain": "Materie", "subdomain": "Polymeren, legeringen en keramische materialen"}, {"domain": "Materie", "subdomain": "Bindingen en stofeigenschappen"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-i-autobanden-vraag11.png$$, $$Leg uit dat de aanwezigheid van kristallijne gebieden een autoband beter bestand tegen vervorming maakt. Gebruik hierbij begrippen op microniveau.$$, array['a1b2c3d4-0002-4000-8000-000000000013', 'a1b2c3d4-0002-4000-8000-000000000014']::uuid[]),
  ('a1b2c3d4-0003-4000-8000-000000000012', 'a1b2c3d4-0001-4000-8000-000000000002', 12,
