   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-i-niacine-vraag14.png$$, $$Geef de vergelijking van deze vorming van picoline. Gebruik structuurformules voor de organische deeltjes.$$, array['a1b2c3d4-0002-4000-8000-000000000019', 'a1b2c3d4-0002-4000-8000-000000000020']::uuid[]),
