   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-i-niacine-vraag15.png$$, $$Zet in de tabel op de uitwerkbijlage achter elk enzym een kruisje in de juiste kolom. Elke kolom moet hierbij één kruisje bevatten.$$, array['a1b2c3d4-0002-4000-8000-000000000021', 'a1b2c3d4-0002-4000-8000-000000000022', 'a1b2c3d4-0002-4000-8000-000000000023']::uuid[]),
