   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-i-niacine-vraag16.png$$, $$Bereken het rendement van deze omzetting.$$, array['a1b2c3d4-0002-4000-8000-000000000019', 'a1b2c3d4-0002-4000-8000-000000000021', 'a1b2c3d4-0002-4000-8000-000000000024']::uuid[]),
