  ('a1b2c3d4-0003-4000-8000-000000000020', 'a1b2c3d4-0001-4000-8000-000000000003', 20,
   '[{"domain": "Materie", "subdomain": "Moleculaire structuur en ruimtelijke bouw"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-i-niacine-vraag20.png$$, $$Teken met behulp van figuur 4 de structuurformule van het uiteinde van de eiwitketen van het receptoreiwit. Dit gedeelte moet bestaan uit de laatste twee aminozuureenheden.$$, array['a1b2c3d4-0002-4000-8000-000000000026']::uuid[]),
  ('a1b2c3d4-0003-4000-8000-000000000021', 'a1b2c3d4-0001-4000-8000-000000000004', 21,
   '[{"domain": "Reacties", "subdomain": "Polymerisatie"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-i-een-pleister-voor-stroom-vraag21.png$$, $$Maak op de uitwerkbijlage het mechanisme compleet.
− Teken in het omkaderde deel de niet-bindende elektronenparen.
− Geef in het omkaderde deel met pijlen weer hoe elektronenparen worden verplaatst tijdens de reactie.$$, array['a1b2c3d4-0002-4000-8000-000000000027', 'a1b2c3d4-0002-4000-8000-000000000028', 'a1b2c3d4-0002-4000-8000-000000000029']::uuid[]),
  ('a1b2c3d4-0003-4000-8000-000000000022', 'a1b2c3d4-0001-4000-8000-000000000004', 22,
   '[{"domain": "Reacties", "subdomain": "Redoxreacties en elektrochemische cel"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-i-een-pleister-voor-stroom-vraag22.png$$, $$Geef met behulp van figuur 2 de vergelijkingen van beide halfreacties. Gebruik molecuulformules voor organische deeltjes.$$, array['a1b2c3d4-0002-4000-8000-000000000030', 'a1b2c3d4-0002-4000-8000-000000000031']::uuid[]),
  ('a1b2c3d4-0003-4000-8000-000000000023', 'a1b2c3d4-0001-4000-8000-000000000004', 23,
   '[{"domain": "Reacties", "subdomain": "Chemisch evenwicht en evenwichtsconstante"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-i-een-pleister-voor-stroom-vraag23.png$$, $$Verklaar dat bij hogere concentraties lactaat de reactiesnelheid minder toeneemt dan bij lagere concentraties.$$, array['a1b2c3d4-0002-4000-8000-000000000032', 'a1b2c3d4-0002-4000-8000-000000000033']::uuid[]),
  ('a1b2c3d4-0003-4000-8000-000000000024', 'a1b2c3d4-0001-4000-8000-000000000004', 24,
   '[{"domain": "Reacties", "subdomain": "Redoxreacties en elektrochemische cel"}, {"domain": "Rekenen en analyse", "subdomain": "Molaire massa en molariteit"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-i-een-pleister-voor-stroom-vraag24.png$$, $$Bereken de massa in gram lactaat (C₃H₅O₃⁻) die in die tijd is omgezet. Neem aan dat in de brandstofcel geen andere reacties optreden. Geef de uitkomst in het juiste aantal significante cijfers.$$, array['a1b2c3d4-0002-4000-8000-000000000030', 'a1b2c3d4-0002-4000-8000-000000000031', 'a1b2c3d4-0002-4000-8000-000000000034']::uuid[]);
